class Solution:
    def __init__(self):
        self.root = TrieNode()

    def insert(self, s):
        root = self.root
        for char in s[::-1]:
            if char not in root.children:
                root.children[char] = TrieNode()
            root = root.children[char]
        root.endOfString = True

    def solve(self, s, prefix):
        root = self.root
        for char in prefix[::-1]:
            if char not in root.children:
                return False
            root = root.children[char]
        return root.endOfString

