// Solution.cpp
#include <iostream>
#include <string>
using namespace std;

class TrieNode {
public:
    char c;
    int freq;
    TrieNode* children[26];
    TrieNode(char c) {
        this->c = c;
        this->freq = 0;
        for (int i = 0; i < 26; i++) {
            this->children[i] = NULL;
        }
    }
};
class Solution {
public:
    TrieNode* root;
    Solution() {
        root = new TrieNode();
    }

    void insert(string s) {
        TrieNode* root = this->root;
        for (int i = s.length() - 1; i >= 0; i--) {
            if (root->children[s[i] - 'a'] == NULL) {
                root->children[s[i] - 'a'] = new TrieNode(s[i]);
            }
            root = root->children[s[i] - 'a'];
        }
        root->freq++;
    }

    bool solve(string s, string prefix) {
        TrieNode* root = this->root;
        for (int i = prefix.length() - 1; i >= 0; i--) {
            if (root->children[prefix[i] - 'a'] == NULL) {
                return false;
            }
            root = root->children[prefix[i] - 'a'];
        }
        return root->freq > 0;
    }
};

int main() {
    Solution s;
    s.insert("abcde");
    result = s.solve("deab", "deab");
    cout << (result ? "True" : "False") << endl;
    return 0;
}
